# GraphQL Schema
type_defs = """
    type Query {
        userProfile(id: ID!): User
        users: [User!]!
        me: User
        post(id: ID!): Post
        posts(authorId: ID): [Post!]!
    }

    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        published: Boolean!
        author: User!
    }
"""

# Resolvers
query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")


@query.field("userProfile")
def resolve_user_profile(_, info, id):
    return USERS.get(id)


@query.field("users")
def resolve_users(_, info):
    return list(USERS.values())


@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if current_user is None:
        return None
    return USERS.get(current_user)


@query.field("post")
def resolve_post(_, info, id):
    return POSTS.get(id)


@query.field("posts")
def resolve_posts(_, info, authorId=None):
    if authorId:
        return [p for p in POSTS.values() if p.author_id == authorId]
    return list(POSTS.values())


# User field resolvers
@user_type.field("posts")
def resolve_user_posts(user, info):
    return [POSTS[pid] for pid in user.post_ids if pid in POSTS]


@user_type.field("id")
def resolve_user_id(user, info):
    return user.id


@user_type.field("username")
def resolve_user_username(user, info):
    return user.username


@user_type.field("bio")
def resolve_user_bio(user, info):
    return user.bio


@user_type.field("email")
def resolve_user_email(user, info):
    """Private field - returns email. Field-level permissions to be added later."""
    current_user = info.context.get("current_user")
    # For now, return the email; field-level permissions will be layered on top
    return user.email


@user_type.field("phone")
def resolve_user_phone(user, info):
    """Private field - returns phone. Field-level permissions to be added later."""
    current_user = info.context.get("current_user")
    return user.phone


@user_type.field("address")
def resolve_user_address(user, info):
    """Private field - returns address. Field-level permissions to be added later."""
    current_user = info.context.get("current_user")
    return user.address


# Post field resolvers
@post_type.field("author")
def resolve_post_author(post, info):
    return USERS.get(post.author_id)


@post_type.field("id")
def resolve_post_id(post, info):
    return post.id


@post_type.field("title")
def resolve_post_title(post, info):
    return post.title


@post_type.field("content")
def resolve_post_content(post, info):
    return post.content


@post_type.field("published")
def resolve_post_published(post, info):
    return post.published


# Create executable schema
schema = make_executable_schema(type_defs, query, user_type, post_type)


# Authentication middleware
class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts the current user from the request.
    Looks for an X-User-ID header to simulate authentication.
    In production, this would verify JWT tokens, session cookies, etc.
    """

    async def dispatch(self, request: Request, call_next):
        user_id = request.headers.get("X-User-ID")
        if user_id and user_id in USERS:
            request.state.current_user = user_id
        else:
            request.state.current_user = None
        response = await call_next(request)
        return response


def get_context_value(request):
    """Build the context for each GraphQL request, including the current user set by middleware."""
    current_user = getattr(request.state, "current_user", None) if hasattr(request, "state") else None
    return {
        "request": request,
        "current_user": current_user,
    }


# Create ASGI app
app = GraphQL(
    schema,
    context_value=get_context_value,
    debug=True,
)


# Wrap with authentication middleware
from starlette.applications import Starlette
from starlette.routing import Route, Mount

starlette_app = Starlette(
    routes=[
        Mount("/", app=app),
    ],
    middleware=[
        Middleware(AuthenticationMiddleware),
    ],
)


